def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                temp = (np.sin(ratio * a * np.pi) + 1) * (a ** 2.8) / (np.cosh(ratio * a) + 1)
                if a % 4 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.12
                score += temp
            if (capacity + item) % 4 == 0 or (capacity - item) % 7 == 0:
                score *= 0.81
            if score > 12:
                score /= 3.1
            if capacity > 150:
                for v in range(2, 8):
                    score += np.log1p((ratio * v) ** 3) / (v + 0.5)
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 3):
                prod *= (ratio + n / (n + 2))
                if prod > 5e6:
                    prod = np.log1p(prod)
                    break
            mod_val = int(prod) % 400
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 0) and ((item * 5) % 4 == 0):
                score += 6.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 7):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.3)
            score += extra_sum / 6
            if score < -3:
                score = abs(score) * 0.9 + 1
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 8):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 2:
                score += 15 + remainder * 0.7 + np.sin(remainder * np.pi/2)
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 20:
                score /= 4
        elif 0.5 < ratio <= 0.9:
            penalty_base = 0
            for p in range(1, 12):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.8) * np.cos(p * ratio * np.pi/2)
                if penalty_base > 60:
                    penalty_base = np.log1p(abs(penalty_base))
                    break
            score = penalty_base * 14
            if capacity < item * 1.07:
                score += 20
            if (int(capacity * 6) % 8 == 0) and (int(item * 9) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.8
                score += 7
            if score > 110:
                score = 110
            for k in range(3, 7):
                score += ((ratio * k) % 1) * (k * 1.9)
        elif 0.9 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.9
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 3.0) / (q + 2) * np.sin(diff * q)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 9
            for z in range(2, 8):
                score += ((diff / (z + 1)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6 + 2
            if score > 1500:
                score = 1500
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5) * np.tanh(diff * r)
                if term > 12000:
                    term = np.sqrt(abs(term))
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.4:
                score += 35
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 2500:
                score = 2500
        else:
            mega_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 20):
                val = ((diff) ** s) * (s ** 4) * np.cos(diff * s)
                if abs(val) > 15000:
                    val = np.cbrt(val)
                mega_penalty += val
            score = mega_penalty * 35
            if capacity < item * 3:
                score += 50
            if (int(capacity * 17) % 7 == 0) and (int(item * 25) % 8 == 0):
                score -= 20
            for y in range(4, 10):
                score += ((diff / y) % 1) * (y * 3)
            if score < 0:
                score = abs(score) * 0.7 + 7
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            for f in range(1, 4):
                score += np.log1p(ratio * capacity / (f + 0.1))
        elif capacity < 7:
            score *= 2.7
            for e in range(1, 5):
                score += (ratio * e) % 1 * e
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
        if fill_value < 0:
            fill_value = abs(fill_value) * 1.1 + 5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
